const budgetCostFor = (
  state: GameState,
  definition: EnemyDefinition
): number | null => {
  const directCost = budgetCostFromDefinition(definition);
  if (directCost !== null) {
    return directCost;
  }

  const rosterDefinition = floorEnemyRoster(state).find(
    (candidate) => candidate.id === definition.id
