  const enemy = state.entities[enemyId];

  if (enemy?.kind !== "enemy" || guard === null || guard === undefined) {
    return { kind: "wait" };
  }

  const post = guardPostFor(enemy);
  const radius = guard.tetherRadiusTiles;

  if (
