 73	    ceilDiv(
 74	      nonNegativeDelta(definition.stats.hp, bandBudget.hp.min),
 75	      statWeights.hpDeltaDivisor,
 76	    ) +
 77	    nonNegativeDelta(definition.stats.attack, bandBudget.attack.min) *
 78	      statWeights.attackDelta +
 79	    nonNegativeDelta(definition.stats.defense, bandBudget.defense.min) *
 80	      statWeights.defenseDelta
 81	  );
 82	};
