 92	export const effectCost = (effect: Effect): number => {
 93	  const verbBase = costWeights.effects.verbs[effect.kind];
 94	  const divisors = costWeights.effects.magnitudeDivisors;
 95	
 96	  switch (effect.kind) {
 97	    case "damage":
 98	      return verbBase + ceilDiv(effect.damage?.amount ?? 0, divisors.damageAmount);
 99	    case "heal":
100	      return verbBase + ceilDiv(effect.heal?.amount ?? 0, divisors.healAmount);
101	    case "apply_status":
102	      return (
103	        verbBase +
104	        ceilDiv(effect.applyStatus?.duration ?? 0, divisors.statusDuration)
105	      );
106	    case "cure_status":
107	      return verbBase + (effect.cureStatus?.status === "all" ? 1 : 0);
108	    case "buff_stat": {
109	      const payload = effect.buffStat;
110	      const magnitudeDuration =
111	        payload === null ? 0 : Math.abs(payload.magnitude) * payload.duration;
112	
113	      return (
114	        verbBase +
115	        ceilDiv(magnitudeDuration, divisors.buffMagnitudeDurationProduct)
116	      );
117	    }
118	    case "nutrition":
119	      return (
120	        verbBase +
121	        ceilDiv(effect.nutrition?.fullness ?? 0, divisors.nutritionFullness)
122	      );
123	    case "teleport_self":
124	    case "teleport_target":
125	    case "reveal":
126	    case "identify":
127	      return verbBase;
128	    case "blink":
129	      return (
130	        verbBase +
131	        ceilDiv(effect.blink?.distanceTiles ?? 0, divisors.blinkDistanceTiles)
132	      );
133	    case "knockback":
134	      return (
135	        verbBase +
136	        ceilDiv(effect.knockback?.pushTiles ?? 0, divisors.knockbackPushTiles) +
137	        ceilDiv(
138	          effect.knockback?.collisionDamage ?? 0,
139	          divisors.knockbackCollisionDamage,
140	        )
141	      );
142	    case "enchant":
143	      return verbBase + (effect.enchant?.bonus ?? 0);
144	    case "summon":
145	      return verbBase + ceilDiv(effect.summon?.count ?? 0, divisors.summonCount);
146	    case "transform":
147	      return verbBase;
148	    case "dig":
149	      return (
150	        verbBase +
151	        ceilDiv(effect.dig?.lengthTiles ?? 0, divisors.digLengthTiles)
152	      );
153	    default:
154	      throw new RangeError(`unsupported enemy effect cost ${String(effect.kind)}`);
155	  }
156	};
