158	export const triggerCost = (trigger: Trigger): number => {
159	  const base = costWeights.effects.trigger[trigger.kind];
160	  const divisors = costWeights.effects.magnitudeDivisors;
161	
162	  switch (trigger.kind) {
163	    case "on_hit":
164	      return (
165	        base +
166	        ceilDiv(
167	          trigger.onHit?.procChancePercent ?? 0,
168	          divisors.procChancePercent,
169	        )
170	      );
171	    case "on_struck":
172	      return (
173	        base +
174	        ceilDiv(
175	          trigger.onStruck?.procChancePercent ?? 0,
176	          divisors.procChancePercent,
177	        )
178	      );
179	    case "use":
180	      return base + ceilDiv(trigger.use?.charges ?? 0, divisors.useCharges);
181	    case "quaff":
182	    case "read":
183	    case "throw_hit":
184	    case "equip_passive":
185	    case "step":
186	      return base;
187	    default:
188	      throw new RangeError(
189	        `unsupported enemy trigger cost ${String(trigger.kind)}`,
190	      );
191	  }
192	};
