194	export const targetingCost = (targeting: TargetingShape): number => {
195	  const base = costWeights.effects.targeting[targeting.kind];
196	  const divisors = costWeights.effects.magnitudeDivisors;
197	
198	  switch (targeting.kind) {
199	    case "bolt":
