207	        ceilDiv(targeting.burst?.radiusTiles ?? 0, divisors.burstRadiusTiles)
208	      );
209	    case "self":
210	    case "melee":
211	    case "floor":
212	      return base;
213	    default:
214	      throw new RangeError(
215	        `unsupported enemy targeting cost ${String(targeting.kind)}`,
216	      );
217	  }
218	};
